sys_script.script:
(function executeRule(current, previous /*null when async*/) {

    var ciSysId = current.cmdb_ci.toString();
    if (!ciSysId) {
        gs.warn('AnomalySignalBridge: No CMDB CI on signal ' + current.sys_id);
        return;
    }

    // Suppress if alert suppression is active
    if (gs.getProperty('u_anomaly.alert_suppression_enabled', 'true') === 'true') {
        if (_isDuplicateWithinWindow(ciSysId, 15)) {
            gs.info('AnomalySignalBridge: Suppressed duplicate signal for CI ' + ciSysId);
            return;
        }
    }

    // Upsert anomaly event
    var eventGr = new GlideRecord('u_anomaly_event');
    eventGr.addQuery('u_configuration_item', ciSysId);
    eventGr.addQuery('u_active', true);
    eventGr.setLimit(1);
    eventGr.query();

    var engine = new ServiceStateEngine(ciSysId);

    if (eventGr.next()) {
        // Existing active event — re-evaluate state
        var newState = engine.evaluateTransition(eventGr.u_state.toString());
        if (newState.toString() !== eventGr.u_state.toString()) {
            eventGr.u_state              = newState;
            eventGr.u_last_evaluated_on  = new GlideDateTime();
            eventGr.u_signal_count       = parseInt(eventGr.u_signal_count) + 1;
            eventGr.update();
            gs.info('AnomalySignalBridge: State transitioned to ' + newState + ' for CI ' + ciSysId);
        }
    } else {
        // New anomaly event
        eventGr.initialize();
        eventGr.u_configuration_item = ciSysId;
        eventGr.u_state              = engine.evaluateTransition(ServiceStateEngine.STATE.NORMAL.toString());
        eventGr.u_signal_source      = current.sys_id;
        eventGr.u_signal_name        = current.name.toString();
        eventGr.u_active             = true;
        eventGr.u_signal_count       = 1;
        eventGr.u_detected_on        = new GlideDateTime();
        eventGr.u_last_evaluated_on  = new GlideDateTime();
        eventGr.insert();
        gs.info('AnomalySignalBridge: New anomaly event created for CI ' + ciSysId);
    }

    function _isDuplicateWithinWindow(ciId, windowMinutes) {
        var windowStart = new GlideDateTime();
        windowStart.addSeconds(-(windowMinutes * 60));

        var dup = new GlideRecord('u_anomaly_event');
        dup.addQuery('u_configuration_item', ciId);
        dup.addQuery('u_detected_on', '>=', windowStart.getValue());
        dup.query();
        return dup.hasNext();
    }

})(current, previous);
